 sents:[{a:"يَخْرُجُ خالِدٌ الْآنَ مِنْ بَيْتِهِ",b:"খালিদ এখন তার বাড়ি থেকে বের হচ্ছে"},{a:"يَذْهَبُ إِلَى الْمَدْرَسَةِ",b:"সে মাদরাসায় যাচ্ছে",img:"🏫"},{a:"يَجْلِسُ خالِدٌ أَمامَ الْمُعَلِّمِ",b:"খালিদ শিক্ষকের সামনে বসে",img:"🧑‍🏫"},{a:"يَرْجِعُ قَبْلَ الْعَصْرِ",b:"সে আসরের আগে ফেরে"},{a:"يَلْعَبُ فِي مَلْعَبِ الْقَرْيَةِ بَعْدَ الْعَصْرِ",b:"সে আসরের পর গ্রামের মাঠে খেলে",img:"🏘️"},{a:"تَخْرُجُ فاطِمَةُ الْآنَ مِنْ غُرْفَتِها",b:"ফাতেমা এখন তার কামরা থেকে বের হচ্ছে"},{a:"بَعْدَ الْمَغْرِبِ تَقْرَأُ وَ تَكْتُبُ",b:"মাগরিবের পর সে পড়ে ও লেখে"},{a:"تَرْجِعُ أُمُّ سُعادَ غَدًا",b:"সুআদের আম্মা আগামীকাল ফিরবেন",img:"👩"}],
