 sents:[{a:"يا ماجِدُ! اِجْلِسْ عَلى مَقْعَدِكَ",b:"হে মাজেদ! তোমার আসনে বসো"},{a:"لا تَجْلِسْ عَلى كُرْسِيِّ الْمُعَلِّمِ",b:"শিক্ষকের চেয়ারে বসো না",img:"🪑"},{a:"اُكْتُبْ بِهٰذَا الْقَلَمِ الْجَيِّدِ",b:"এই ভালো কলমটি দিয়ে লেখো",img:"🖊️"},{a:"يا لَيْلى! لا تَخْرُجِي إِلَى الطَّرِيقِ",b:"হে লাইলা! রাস্তায় বের হয়ো না",img:"🛣️"},{a:"لا تَخْرُجْ مِنَ الْمَسْجِدِ قَبْلَ الصَّلاةِ",b:"নামাযের আগে মসজিদ থেকে বের হয়ো না",img:"🕌"},{a:"أَيُّهَا الْإِنْسانُ! اِرْجِعْ إِلى رَبِّكَ",b:"হে মানুষ! তোমার রবের দিকে ফিরে এসো"},{a:"نَمْ يا وَلَدِي عَلَى اسْمِ اللّٰهِ",b:"ঘুমাও আমার ছেলে, আল্লাহর নামে",img:"👦"},{a:"اِفْتَحْ كِتابَكَ وَ اقْرَأْ دَرْسَكَ",b:"তোমার বই খোলো এবং তোমার পাঠ পড়ো",img:"📖"}],
